CREATE TABLE IF NOT EXISTS public.payment_requests (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), table_id uuid REFERENCES public.dining_tables(id) ON DELETE SET NULL, table_name text, order_id uuid REFERENCES public.orders(id) ON DELETE SET NULL, amount numeric NOT NULL DEFAULT 0, method text NOT NULL CHECK (method IN ('cash','card_terminal','stripe')), status text NOT NULL DEFAULT 'new' CHECK (status IN ('new','handled','paid','cancelled')), note text, created_at timestamptz NOT NULL DEFAULT now(), handled_at timestamptz); ALTER TABLE public.payment_requests ENABLE ROW LEVEL SECURITY; CREATE POLICY "pr_select" ON public.payment_requests FOR SELECT TO authenticated USING (true); CREATE POLICY "pr_update" ON public.payment_requests FOR UPDATE TO authenticated USING (true) WITH CHECK (true); CREATE INDEX IF NOT EXISTS payment_requests_status_idx ON public.payment_requests (status, created_at DESC); ALTER PUBLICATION supabase_realtime ADD TABLE public.payment_requests;